import React from 'react';

const Bio = ({ bio }) => {
  const bioLines = bio.split('\n');
  
  return (
    <div className="bio">
      {bioLines.map((line, i) => (
        <p key={i} dangerouslySetInnerHTML={{ __html: line }} />
      ))}
    </div>
  );
};

export default Bio;